mapper.select:
SELECT comment_id, post_id, parent_id, like_count
FROM forum_comment
WHERE comment_id = #{commentId}

SELECT p.post_id, p.section_id, p.title, p.content, p.user_id, p.is_top, p.is_essence, p.status, p.collect_count, p.comment_count, p.created_time, p.updated_time, p.last_comment_time, u.nickname, u.avatar_url AS avatarUrl, u.username AS username FROM forum_post p LEFT JOIN user u ON p.user_id = u.user_id
p.section_id = #{sectionId}
ORDER BY p.created_time DESC

SELECT COUNT(*)
FROM forum_collect
WHERE post_id = #{postId} AND user_id = #{userId}

mapper.update:
UPDATE forum_post p
SET p.comment_count = (
    SELECT COALESCE(COUNT(*), 0)
    FROM forum_comment c
    WHERE c.post_id = p.post_id
);

UPDATE forum_post
SET is_top = 1
WHERE post_id = #{postId}

UPDATE forum_post
SET is_essence = 1
WHERE post_id = #{postId}

UPDATE forum_post
SET is_top = 0
WHERE post_id = #{postId}

UPDATE forum_post
SET is_essence = 0
WHERE post_id = #{postId}
